    end
  end

  defp validate_url(_), do: {:error, :invalid_url}

  defp sanitize_url(url) do
    uri = URI.parse(url)
    
    sanitized = %URI{
      scheme: uri.scheme,
      host: String.downcase(uri.host || ""),
      port: uri.port,
      path: uri.path,
      query: uri.query,
      fragment: nil,
      userinfo: nil
    }
    
    {:ok, URI.to_string(sanitized)}
  end

  defp check_ssrf_protection(url) do
    uri = URI.parse(url)
    host = String.downcase(uri.host || "")
    
    cond do
      host in @blocked_hosts ->
        {:error, :blocked_host}
      
      String.contains?(host, ["localhost", "127.0.0.1", "0.0.0.0"]) ->
        {:error, :blocked_host}
      
      is_private_ip?(host) ->
        {:error, :ssrf_attempt}
      
      true ->
